import WidgetKit
import SwiftUI
import AppIntents

struct HydrationIntent: AppIntent {
    static var title: LocalizedStringResource = 'Hydration Level'
    @Parameter(title: 'Goal (oz)') var goal: Int
}

struct HydrationWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: 'HydrationWidget',
            intent: HydrationIntent.self,
            provider: .static
        ) { entry in
            Text("Hydration: 40/" + String(entry.goal) + " oz")
        }
    }
}

